const https = require('https');
// Get astroalign from the correct repo
https.get('https://github.com/toros-astro/astroalign', {headers: {'User-Agent': 'Mozilla/5.0'}}, res => {
  let data = '';
  res.on('data', c => data += c);
  res.on('end', () => {
    console.log('toros-astro/astroalign:', res.statusCode);
    const text = data.replace(/<[^>]*>/g, ' ').replace(/\\s+/g, ' ').trim();
    // Extract readme
    const readmeIdx = text.indexOf('README');
    if (readmeIdx > 0) console.log(text.substring(readmeIdx, readmeIdx + 5000));
    else console.log(text.substring(0, 3000));
  });
}).on('error', e => console.log('error:', e.message));

