  let data = '';
  res.on('data', c => data += c);
  res.on('end', () => {
    console.log('\\nDSS theory:', res.statusCode);
    const text = data.replace(/<[^>]*>/g, ' ').replace(/\\s+/g, ' ').trim();
    console.log(text.substring(0, 4000));
  });
}).on('error', e => console.log('DSS error:', e.message));
"

node -e "
const https = require('https');
// Try github via API for astroalign
https.get('https://api.github.com/repos/toros-astro/astroalign', {headers: {'User-Agent': 'Mozilla/5.0'}}, res => {
  let data = '';
  res.on('data', c => data += c);
  res.on('end', () => {
    try {
      const j = JSON.parse(data);
      console.log('astroalign:', j.full_name, 'stars:', j.stargazers_count, 'desc:', j.description);
    } catch(e) { console.log('parse error'); }
  });
}).on('error', e => console.log('error:', e.message));

// Try to find the actual redirect URL
https.get('https://github.com/toros-astro/astroalign', {headers: {'User-Agent': 'Mozilla/5.0'}}, res => {
  console.log('redirect:', res.headers.location);
  if (res.headers.location) {
    https.get(res.headers.location, {headers: {'User-Agent': 'Mozilla/5.0'}}, res2 => {
      let data = '';
      res2.on('data', c => data += c);
      res2.on('end', () => {
        console.log('final:', res2.statusCode);
        const text = data.replace(/<[^>]*>/g, ' ').replace(/\\s+/g, ' ').trim();
        const ri = text.toLowerCase().indexOf('readme');
        if (ri > 0) console.log(text.substring(ri, ri + 4000));
      });
    });
  }
}).on('error', e => console.log('error:', e.message));
"

